const renderCourseMaterialManagement = () => {
    const [form] = Form.useForm();
    
    const columns = [
        {
            title: 'Type',
            dataIndex: 'type',
            key: 'type',
            render: (type) => {
                const iconMap = {
                    pdf: <FileOutlined style={{ color: '#ff4d4f' }} />,
                    video: <VideoCameraOutlined style={{ color: '#1890ff' }} />,
                    audio: <AudioOutlined style={{ color: '#52c41a' }} />
                };
                return <span>{iconMap[type]} {type.toUpperCase()}</span>;
            }
        },
        {
            title: 'Title',
            dataIndex: 'title',
            key: 'title',
        },
        {
            title: 'Course',
            dataIndex: 'course',
            key: 'course',
        },
        {
            title: 'Upload Date',
            dataIndex: 'uploadDate',
            key: 'uploadDate',
            render: (date) => new Date(date).toLocaleDateString()
        },
        {
            title: 'Size',
            dataIndex: 'size',
            key: 'size',
            render: (size) => `${(size / 1024 / 1024).toFixed(2)} MB`
        },
        {
            title: 'Actions',
            key: 'actions',
            render: (_, record) => (
                <Space>
                    <Button icon={<EyeOutlined />} size="small">View</Button>
                    <Button icon={<EditOutlined />} size="small">Edit</Button>
                    <Popconfirm title="Delete this material?" onConfirm={() => handleDeleteMaterial(record.id)}>
                        <Button icon={<DeleteOutlined />} size="small" danger>Delete</Button>
                    </Popconfirm>
                </Space>
            )
        }
    ];

    const handleDeleteMaterial = async (id) => {
        setCourseMaterials(prev => prev.filter(item => item.id !== id));
        notification.success({ message: 'Material deleted successfully!' });
    };

    const handleUploadSubmit = async (values) => {
        const newMaterial = {
            id: Date.now(),
            ...values,
            uploadDate: new Date().toISOString(),
            size: 5 * 1024 * 1024 // Mock size
        };
        setCourseMaterials(prev => [...prev, newMaterial]);
        setShowMaterialUploadModal(false);
        form.resetFields();
        notification.success({ message: 'Material uploaded successfully!' });
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold">Course Materials</h2>
                    <p className="text-gray-600">Manage PDFs, videos, and audio files</p>
                </div>
                <Button 
                    type="primary" 
                    icon={<PlusOutlined />}
                    onClick={() => setShowMaterialUploadModal(true)}
                >
                    Upload Material
                </Button>
            </div>

            <Card>
                <Table 
                    dataSource={courseMaterials} 
                    columns={columns} 
                    pagination={{ pageSize: 10 }}
                    rowKey="id"
                />
            </Card>

            {/* Upload Modal */}
            <Modal
                title="Upload Course Material"
                open={showMaterialUploadModal}
                onCancel={() => setShowMaterialUploadModal(false)}
                footer={null}
                width={600}
            >
                <Form form={form} layout="vertical" onFinish={handleUploadSubmit}>
                    <Form.Item name="title" label="Title" rules={[{ required: true }]}>
                        <Input placeholder="Enter material title" />
                    </Form.Item>
                    <Form.Item name="course" label="Course" rules={[{ required: true }]}>
                        <Select placeholder="Select course">
                            <Select.Option value="javascript">JavaScript Fundamentals</Select.Option>
                            <Select.Option value="react">React Development</Select.Option>
                            <Select.Option value="node">Node.js Backend</Select.Option>
                        </Select>
                    </Form.Item>
                    <Form.Item name="type" label="Material Type" rules={[{ required: true }]}>
                        <Radio.Group>
                            <Radio value="pdf">📄 PDF Document</Radio>
                            <Radio value="video">🎥 Video</Radio>
                            <Radio value="audio">🎵 Audio</Radio>
                        </Radio.Group>
                    </Form.Item>
                    <Form.Item name="description" label="Description">
                        <Input.TextArea rows={3} placeholder="Enter description" />
                    </Form.Item>
                    <Form.Item name="file" label="File Upload">
                        <Upload.Dragger>
                            <p className="ant-upload-drag-icon">
                                <UploadOutlined />
                            </p>
                            <p className="ant-upload-text">Click or drag file to upload</p>
                            <p className="ant-upload-hint">Support for PDF, MP4, MP3 files</p>
                        </Upload.Dragger>
                    </Form.Item>
                    <Form.Item>
                        <Space>
                            <Button type="primary" htmlType="submit">Upload</Button>
                            <Button onClick={() => setShowMaterialUploadModal(false)}>Cancel</Button>
                        </Space>
                    </Form.Item>
                </Form>
            </Modal>
        </div>
    );
};

const renderQuizEngine = () => {
    const [form] = Form.useForm();
    
    const quizColumns = [
        {
            title: 'Quiz Title',
            dataIndex: 'title',
            key: 'title',
        },
        {
            title: 'Course',
            dataIndex: 'course',
            key: 'course',
        },
        {
            title: 'Questions',
            dataIndex: 'questions',
            key: 'questions',
            render: (questions) => `${questions.length} questions`
        },
        {
            title: 'Time Limit',
            dataIndex: 'timeLimit',
            key: 'timeLimit',
            render: (time) => `${time} minutes`
        },
        {
            title: 'Status',
            dataIndex: 'status',
            key: 'status',
            render: (status) => (
                <Tag color={status === 'active' ? 'green' : 'orange'}>
                    {status.toUpperCase()}
                </Tag>
            )
        },
        {
            title: 'Actions',
            key: 'actions',
            render: (_, record) => (
                <Space>
                    <Button icon={<EyeOutlined />} size="small">Preview</Button>
                    <Button icon={<EditOutlined />} size="small">Edit</Button>
                    <Button icon={<DeleteOutlined />} size="small" danger>Delete</Button>
                </Space>
            )
        }
    ];

    const handleCreateQuiz = async (values) => {
        const newQuiz = {
            id: Date.now(),
            ...values,
            questions: currentQuizQuestions,
            createdDate: new Date().toISOString(),
            status: 'active'
        };
        setQuizzes(prev => [...prev, newQuiz]);
        setShowQuizModal(false);
        setCurrentQuizQuestions([]);
        form.resetFields();
        notification.success({ message: 'Quiz created successfully!' });
    };

    const addQuestion = () => {
        const newQuestion = {
            id: Date.now(),
            question: '',
            type: 'multiple-choice',
            options: ['', '', '', ''],
            correctAnswer: 0,
            points: 1
        };
        setCurrentQuizQuestions(prev => [...prev, newQuestion]);
    };

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold">Quiz Engine</h2>
                    <p className="text-gray-600">Create and manage quizzes with automatic grading</p>
                </div>
                <Button 
                    type="primary" 
                    icon={<PlusOutlined />}
                    onClick={() => setShowQuizModal(true)}
                >
                    Create Quiz
                </Button>
            </div>

            <Card>
                <Table 
                    dataSource={quizzes} 
                    columns={quizColumns} 
                    pagination={{ pageSize: 10 }}
                    rowKey="id"
                />
            </Card>

            {/* Create Quiz Modal */}
            <Modal
                title="Create New Quiz"
                open={showQuizModal}
                onCancel={() => setShowQuizModal(false)}
                footer={null}
                width={800}
            >
                <Form form={form} layout="vertical" onFinish={handleCreateQuiz}>
                    <Row gutter={16}>
                        <Col span={12}>
                            <Form.Item name="title" label="Quiz Title" rules={[{ required: true }]}>
                                <Input placeholder="Enter quiz title" />
                            </Form.Item>
                        </Col>
                        <Col span={12}>
                            <Form.Item name="course" label="Course" rules={[{ required: true }]}>
                                <Select placeholder="Select course">
                                    <Select.Option value="javascript">JavaScript</Select.Option>
                                    <Select.Option value="react">React</Select.Option>
                                    <Select.Option value="node">Node.js</Select.Option>
                                </Select>
                            </Form.Item>
                        </Col>
                    </Row>
                    <Row gutter={16}>
                        <Col span={12}>
                            <Form.Item name="timeLimit" label="Time Limit (minutes)" rules={[{ required: true }]}>
                                <InputNumber min={5} max={180} placeholder="30" style={{ width: '100%' }} />
                            </Form.Item>
                        </Col>
                        <Col span={12}>
                            <Form.Item name="passingScore" label="Passing Score (%)">
                                <InputNumber min={0} max={100} placeholder="70" style={{ width: '100%' }} />
                            </Form.Item>
                        </Col>
                    </Row>
                    
                    <Divider>Questions</Divider>
                    
                    <div className="space-y-4">
                        {currentQuizQuestions.map((question, index) => (
                            <Card key={question.id} size="small">
                                <div className="space-y-3">
                                    <Input 
                                        placeholder={`Question ${index + 1}`}
                                        value={question.question}
                                        onChange={(e) => {
                                            const updated = [...currentQuizQuestions];
                                            updated[index].question = e.target.value;
                                            setCurrentQuizQuestions(updated);
                                        }}
                                    />
                                    {question.options.map((option, optionIndex) => (
                                        <Input 
                                            key={optionIndex}
                                            placeholder={`Option ${optionIndex + 1}`}
                                            value={option}
                                            onChange={(e) => {
                                                const updated = [...currentQuizQuestions];
                                                updated[index].options[optionIndex] = e.target.value;
                                                setCurrentQuizQuestions(updated);
                                            }}
                                        />
                                    ))}
                                    <Select 
                                        placeholder="Correct Answer"
                                        value={question.correctAnswer}
                                        onChange={(value) => {
                                            const updated = [...currentQuizQuestions];
                                            updated[index].correctAnswer = value;
                                            setCurrentQuizQuestions(updated);
                                        }}
                                        style={{ width: '200px' }}
                                    >
                                        {question.options.map((_, optionIndex) => (
                                            <Select.Option key={optionIndex} value={optionIndex}>
                                                Option {optionIndex + 1}
                                            </Select.Option>
                                        ))}
                                    </Select>
                                </div>
                            </Card>
                        ))}
                        
                        <Button type="dashed" onClick={addQuestion} block>
                            <PlusOutlined /> Add Question
                        </Button>
                    </div>

                    <div className="mt-6">
                        <Space>
                            <Button type="primary" htmlType="submit">Create Quiz</Button>
                            <Button onClick={() => setShowQuizModal(false)}>Cancel</Button>
                        </Space>
                    </div>
                </Form>
            </Modal>
        </div>
    );
};

